// Parse Google News RSS XML
const items = [];
for (const input of $input.all()) {
  const body = input.json.data || '';
  const regex = /<item>[\s\S]*?<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>[\s\S]*?<link>([\s\S]*?)<\/link>[\s\S]*?<pubDate>([\s\S]*?)<\/pubDate>[\s\S]*?<\/item>/g;
  let match;
  while ((match = regex.exec(body)) !== null) {
    items.push({
      json: {
        title: match[1].trim(),
        url: match[2].trim(),
        source: 'Google News',
        publishedAt: match[3].trim(),
        raw: match[1]
      }
    });
  }
}
return items.length > 0 ? items : [{ json: { title: 'No items', url: '', source: 'Google News', publishedAt: new Date().toISOString(), raw: '' } }];

// Get first 10 HN story IDs and fetch details
const ids = $input.first().json;
if (!Array.isArray(ids)) return [];
const top10 = ids.slice(0, 10);
return top10.map(id => ({ json: { storyId: id } }));

// Parse Reddit posts
const posts = [];
const data = $input.first().json;
if (data && data.data && data.data.children) {
  for (const child of data.data.children) {
    const post = child.data;
    if (post && post.title) {
      posts.push({
        json: {
          title: post.title,
          url: `https://reddit.com${post.permalink}`,
          source: 'Reddit r/SaaS',
          publishedAt: new Date(post.created_utc * 1000).toISOString(),
          score: post.score,
          raw: post.selftext || post.title
        }
      });
    }
  }
}
return posts.length > 0 ? posts : [{ json: { title: '', url: '', source: 'Reddit', publishedAt: new Date().toISOString() } }];

// Filter: remove empty, duplicates, and non-relevant items
const seen = new Set();
const keywords = ['saas', 'software', 'automation', 'ai tool', 'startup', 'niche', 'vertical', 'smb', 'small business', 'workflow', 'crm', 'erp', 'api', 'platform', 'subscription'];
const results = [];

for (const item of $input.all()) {
  const title = (item.json.title || '').toLowerCase();
  const url = item.json.url || '';

  if (!title || title === 'no items' || seen.has(title)) continue;

  const relevant = keywords.some(kw => title.includes(kw));
  if (!relevant) continue;

  seen.add(title);
  results.push({
    json: {
      title: item.json.title,
      url: item.json.url || '',
      source: item.json.source || 'Unknown',
      publishedAt: item.json.publishedAt || new Date().toISOString(),
      raw: item.json.raw || item.json.title
    }
  });
}

return results.slice(0, 20); // Max 20 ideas per run

// Parse Claude response and calculate composite score
const results = [];

for (const item of $input.all()) {
  try {
    const response = item.json;
    let scoreData = null;

    // Extract JSON from Claude response
    if (response.content && response.content[0] && response.content[0].text) {
      const text = response.content[0].text;
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        scoreData = JSON.parse(jsonMatch[0]);
      }
    }

    if (!scoreData) continue;

    // Weighted composite score
    const weights = {
      market: 0.15,
      automation: 0.20,
      pain: 0.15,
      competition: 0.10,
      willingnessToPay: 0.10,
      margin: 0.10,
      build: 0.10,
      timing: 0.10
    };

    let composite = 0;
    for (const [key, weight] of Object.entries(weights)) {
      composite += (scoreData[key] || 0) * weight;
    }
    composite = Math.round(composite * 10) / 10;

    // Verdict
    let verdict = 'KILL';
    if (composite >= 8.0) verdict = 'BUILD';
    else if (composite >= 6.5) verdict = 'BET';
    else if (composite >= 4.5) verdict = 'FLIP';

    results.push({
      json: {
        title: $('Фильтр и дедупликация').item.json.title,
        source: $('Фильтр и дедупликация').item.json.source,
        sourceUrl: $('Фильтр и дедупликация').item.json.url,
        scoreComposite: composite,
        verdict,
        verdictReason: scoreData.summary || '',
        scores: {
          market: scoreData.market,
          automation: scoreData.automation,
          pain: scoreData.pain,
          competition: scoreData.competition,
          willingnessToPay: scoreData.willingnessToPay,
          margin: scoreData.margin,
          build: scoreData.build,
          timing: scoreData.timing
        },
        discoveredAt: new Date().toISOString()
      }
    });
  } catch (e) {
    // Skip failed items
  }
}

return results;

// Auto-delete KILL/FLIP ideas older than 10 days
const tenDaysAgo = new Date();
tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
return [{
  json: {
    cutoffDate: tenDaysAgo.toISOString(),
    message: `Cleaning ideas before ${tenDaysAgo.toISOString()}`
  }
}];

const allItems = $input.all();
const saved = allItems.length;
return [{
  json: {
    status: 'success',
    ideasSaved: saved,
    timestamp: new Date().toISOString(),
    message: `Discovery complete: ${saved} ideas saved`
  }
}];
